 1	import type { FC } from 'react';
 2	
 3	import { ConsoleTimestamp } from '@components/ConsoleTimestamp/ConsoleTimestamp';
 4	import SectionHeading from '@components/headers/SectionHeading';
 5	import type { V1beta1PlanStatusMigrationVms } from '@kubev2v/types';
 6	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 8	import { VirtualMachineModelGroupVersionKind } from '@utils/crds/common/models';
 9	import { useForkliftTranslation } from '@utils/i18n';
10	
11	type MigrationVirtualMachineTableProps = {
12	  vmCreated: boolean;
13	  statusVM: V1beta1PlanStatusMigrationVms | undefined;
14	  targetNamespace: string;
15	};
16	
17	const MigrationVirtualMachineTable: FC<MigrationVirtualMachineTableProps> = ({
18	  statusVM,
19	  targetNamespace,
20	  vmCreated,
21	}) => {
22	  const { t } = useForkliftTranslation();
23	  if (!vmCreated) {
24	    return null;
25	  }
26	
27	  return (
28	    <>
29	      <SectionHeading
30	        text={t('Virtual machine')}
31	        textComponent="h3"
32	        className="migration-status-expanded-page__resource-list-header"
33	      />
34	      <Table>
35	        <Thead>
36	          <Tr>
37	            <Th width={40}>{t('Name')}</Th>
38	            <Th width={20}>{t('Description')}</Th>
39	            <Th>{t('Completed at')}</Th>
40	          </Tr>
41	        </Thead>
42	        <Tbody>
43	          <Tr key="vm">
44	            <Td width={40}>
45	              <ResourceLink
46	                groupVersionKind={VirtualMachineModelGroupVersionKind}
47	                name={statusVM?.name}
48	                namespace={targetNamespace}
49	              />
50	            </Td>
51	            <Td width={20}>{vmCreated ? t('Migrated') : t('Not yet migrated')}</Td>
52	            <Td>
53	              <ConsoleTimestamp showGlobalIcon={false} timestamp={statusVM?.completed} />
54	            </Td>
55	          </Tr>
56	        </Tbody>
57	      </Table>
58	    </>
59	  );
60	};
61	
62	export default MigrationVirtualMachineTable;

